#!/usr/bin/env python3
"""
百度网盘 OpenClaw 插件
功能：列出文件、下载文件、上传文件
"""

import requests
import json
import os
import sys
from urllib.parse import urlencode

# 配置
BAIDU_PCS_API = "https://pan.baidu.com/rest/2.0/xpan"
BDUSS = ""
COOKIES = {"BDUSS": BDUSS}

def get_filelist(path="/", limit=100):
    """列出目录下的文件"""
    url = f"{BAIDU_PCS_API}/file?method=list"
    params = {
        "dir": path,
        "order": "name",
        "start": 0,
        "limit": limit,
        "web": 1,
        "clienttype": 0,
        "webfrom": 0
    }
    response = requests.get(url, params=params, cookies=COOKIES)
    data = response.json()

    if data.get("errno") == 0:
        return data.get("list", [])
    else:
        print(f"错误: {data}")
        return []

def download_file(path, output_dir="/home/lang/works"):
    """下载文件"""
    # 获取下载链接
    url = f"{BAIDU_PCS_API}/file?method=download"
    params = {
        "path": path,
        "clienttype": 0,
        "web": 1
    }
    response = requests.get(url, params=params, cookies=COOKIES, allow_redirects=False)

    if response.status_code == 302:
        download_url = response.headers.get("Location")
        filename = os.path.basename(path)
        output_path = os.path.join(output_dir, filename)

        print(f"下载: {path} -> {output_path}")
        r = requests.get(download_url, cookies=COOKIES)
        with open(output_path, 'wb') as f:
            f.write(r.content)
        print(f"完成: {output_path}")
        return output_path
    else:
        print(f"获取下载链接失败: {response.text}")
        return None

def upload_file(local_path, remote_path="/", ondup="overwrite"):
    """上传文件"""
    url = f"{BAIDU_PCS_API}/file?method=upload"
    params = {
        "dir": remote_path,
        "ondup": ondup
    }
    files = {"file": open(local_path, "rb")}
    response = requests.post(url, params=params, files=files, cookies=COOKIES)
    data = response.json()

    if data.get("errno") == 0:
        print(f"上传成功: {local_path} -> {remote_path}/{os.path.basename(local_path)}")
        return True
    else:
        print(f"上传失败: {data}")
        return False

def search_file(keyword):
    """搜索文件"""
    url = f"{BAIDU_PCS_API}/file?method=search"
    params = {
        "dir": "/",
        "key": keyword,
        "recursion": 1,
        "limit": 100,
        "clienttype": 0,
        "web": 1
    }
    response = requests.get(url, params=params, cookies=COOKIES)
    data = response.json()

    if data.get("errno") == 0:
        return data.get("list", [])
    else:
        print(f"搜索失败: {data}")
        return []

if __name__ == "__main__":
    if len(sys.argv) < 2:
        print("用法:")
        print("  python3 baidupan.py list [路径]      - 列出文件")
        print("  python3 baidupan.py download [路径]  - 下载文件")
        print("  python3 baidupan.py upload [本地路径] [远程路径] - 上传文件")
        print("  python3 baidupan.py search [关键词]  - 搜索文件")
        sys.exit(0)

    command = sys.argv[1]

    if command == "list":
        path = sys.argv[2] if len(sys.argv) > 2 else "/"
        files = get_filelist(path)
        for f in files:
            ftype = "📁" if f.get("isdir") == 1 else "📄"
            size = f.get("size", 0)
            print(f"{ftype} {f.get('server_filename')} ({size} bytes)")

    elif command == "download":
        if len(sys.argv) > 2:
            download_file(sys.argv[2])
        else:
            print("请指定文件路径")

    elif command == "upload":
        if len(sys.argv) > 2:
            local = sys.argv[2]
            remote = sys.argv[3] if len(sys.argv) > 3 else "/"
            upload_file(local, remote)
        else:
            print("请指定本地文件路径")

    elif command == "search":
        if len(sys.argv) > 2:
            results = search_file(sys.argv[2])
            for f in results:
                print(f"📄 {f.get('server_filename')} - {f.get('size')} bytes")
        else:
            print("请指定搜索关键词")

    else:
        print(f"未知命令: {command}")

