            files.append(f\"📄 {f.get('server_filename')} ({f.get('size', 0):,} bytes)\")

    print(f\"文件夹 ({len(dirs)}):\")
    for d in dirs:
        print(d)
    if files:
        print(f\"\\n文件 ({len(files)}):\")
        for f in files:
            print(f)
else:
